def create_configuration_directories():
    """Create all necessary configuration directories for the library."""
    directories = [CONFIG_DIR, RESOURCES_DIR, LOGS_DIR, CACHE_DIR]

    for directory in directories:
        if not os.path.exists(directory):
            os.makedirs(directory, exist_ok=True)
            print(f"[Setup] Created directory: {directory}")
        else:
            print(f"[Setup] Directory already exists: {directory}")

    # Create subdirectories for resources
    resource_subdirs = ["schemas", "templates", "defaults"]
    for subdir in resource_subdirs:
        subdir_path = os.path.join(RESOURCES_DIR, subdir)
        if not os.path.exists(subdir_path):
            os.makedirs(subdir_path, exist_ok=True)
            print(f"[Setup] Created resource subdirectory: {subdir_path}")


def download_additional_resources():
    """Download additional resources required by the library."""
    print("[Setup] Downloading additional resources...")

    for filename, url in ADDITIONAL_RESOURCES.items():
        target_path = os.path.join(RESOURCES_DIR, filename)

        if os.path.exists(target_path):
            print(f"[Setup] Resource already exists, skipping: {filename}")
            continue

        try:
            print(f"[Setup] Downloading {filename} from {url}...")
            urllib.request.urlretrieve(url, target_path)
            print(f"[Setup] Successfully downloaded: {filename}")
        except urllib.error.URLError as e:
            print(f"[Setup] Warning: Could not download {filename}: {e}")
            print(f"[Setup] Creating placeholder for {filename}...")
            _create_placeholder_resource(target_path, filename)
        except Exception as e:
            print(f"[Setup] Warning: Unexpected error downloading {filename}: {e}")
            _create_placeholder_resource(target_path, filename)


def _create_placeholder_resource(target_path, filename):
    """Create a placeholder resource file when download fails."""
    if filename.endswith(".yaml"):
        content = f"# Placeholder for {filename}\n# Replace with actual configuration\n---\nversion: '{LIBRARY_VERSION}'\n"
    elif filename.endswith(".json"):
        content = json.dumps({
            "placeholder": True,
            "filename": filename,
            "version": LIBRARY_VERSION,
            "note": "Replace with actual resource file"
        }, indent=2)
    else:
        content = f"Placeholder for {filename}. Replace with actual resource."

    with open(target_path, "w") as f:
        f.write(content)
    print(f"[Setup] Created placeholder: {target_path}")


def setup_environment_variables():
    """Set up environment variables and persist them to a config file."""
    print("[Setup] Setting up environment variables...")

    # Set environment variables for the current process
    for key, value in DEFAULT_ENV_VARIABLES.items():
        if key not in os.environ:
            os.environ[key] = value
            print(f"[Setup] Set environment variable: {key}={value}")
        else:
            print(f"[Setup] Environment variable already set: {key}={os.environ[key]}")

    # Persist environment configuration to a JSON file
    env_config = {
        "library_name": LIBRARY_NAME,
        "library_version": LIBRARY_VERSION,
        "environment_variables": DEFAULT_ENV_VARIABLES,
        "installation_path": os.path.dirname(os.path.abspath(__file__)),
        "python_version": sys.version,
    }

    with open(ENV_FILE, "w") as f:
        json.dump(env_config, f, indent=4)
    print(f"[Setup] Environment configuration saved to: {ENV_FILE}")

    # Create shell script for environment variable sourcing
    _create_shell_env_script()


def _create_shell_env_script():
    """Create shell scripts to source environment variables."""
    # Bash/Zsh script
    bash_script_path = os.path.join(CONFIG_DIR, "env_setup.sh")
    with open(bash_script_path, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Environment setup for {LIBRARY_NAME} v{LIBRARY_VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env_setup.sh\n\n")
        for key, value in DEFAULT_ENV_VARIABLES.items():
            f.write(f'export {key}="{value}"\n')
        f.write(f'\necho "{LIBRARY_NAME} environment variables loaded."\n')
    os.chmod(bash_script_path, 0o755)
    print(f"[Setup] Created bash env script: {bash_script_path}")

    # Fish shell script
    fish_script_path = os.path.join(CONFIG_DIR, "env_setup.fish")
    with open(fish_script_path, "w") as f:
        f.write(f"# Environment setup for {LIBRARY_NAME} v{LIBRARY_VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env_setup.fish\n\n")
        for key, value in DEFAULT_ENV_VARIABLES.items():
            f.write(f'set -gx {key} "{value}"\n')
        f.write(f'\necho "{LIBRARY_NAME} environment variables loaded."\n')
    print(f"[Setup] Created fish env script: {fish_script_path}")


