        if self.config_dir:
            CONFIG_DIR = os.path.expanduser(self.config_dir)
            RESOURCES_DIR = os.path.join(CONFIG_DIR, "resources")
            LOGS_DIR = os.path.join(CONFIG_DIR, "logs")
            CACHE_DIR = os.path.join(CONFIG_DIR, "cache")
            ENV_FILE = os.path.join(CONFIG_DIR, "env_config.json")
            DEFAULT_ENV_VARIABLES["INTERNAL_TOOLKIT_HOME"] = CONFIG_DIR
            DEFAULT_ENV_VARIABLES["INTERNAL_TOOLKIT_RESOURCES"] = RESOURCES_DIR
            DEFAULT_ENV_VARIABLES["INTERNAL_TOOLKIT_LOG_DIR"] = LOGS_DIR
            DEFAULT_ENV_VARIABLES["INTERNAL_TOOLKIT_CACHE_DIR"] = CACHE_DIR

        # Run post-install tasks
        print("\n[Setup] Running post-installation tasks...")
        create_configuration_directories()

        if not self.skip_resources:
            download_additional_resources()
        else:
            print("[Setup] Skipping resource downloads (--skip-resources)")

        if not self.skip_env_setup:
            setup_environment_variables()
        else:
            print("[Setup] Skipping environment setup (--skip-env-setup)")

        generate_default_config()
        print("[Setup] Installation complete!\n")


